114→          y2={renderData.line.end.y}
115→          stroke="var(--color-selection)"
116→          strokeWidth={2}
117→          strokeDasharray="6 3"
118→          vectorEffect="non-scaling-stroke"
119→        />
120→        <rect
121→          data-handle="start"
122→          x={sectionCut.startPoint.x - handleR / 2}
123→          y={sectionCut.startPoint.y - handleR / 2}
124→          width={handleR}
125→          height={handleR}
126→          fill="white"
127→          stroke="var(--color-selection)"
128→          strokeWidth={2}
129→          vectorEffect="non-scaling-stroke"
