146→  }
147→
148→  if (selectedType === 'annotation') {
149→    const figure = getManualAnnotationFigure(floor, selectedId);
150→    if (!figure) return null;
151→    return (
152→      <g>
153→        {figure.extensionLines.map((line, index) => (
154→          <line
155→            key={`annotation-ext-${index}`}
