291→            key={i}
292→            x={p.x - handleR / 2}
293→            y={p.y - handleR / 2}
294→            width={handleR}
295→            height={handleR}
296→            fill="white"
297→            stroke="var(--color-selection)"
298→            strokeWidth={2}
299→            vectorEffect="non-scaling-stroke"
300→            style={{ cursor: 'move' }}
301→          />
302→        ))}
303→      </g>
