**sofa (2000mm x 900mm) -- Sofa with Cushions:**

```jsx
case 'sofa': {
  const armW = width * 0.07;
  const backH = depth * 0.22;
  const cushionGap = width * 0.005;
  const seatLeft = -hw + armW;
  const seatRight = hw - armW;
  const seatTop = -hd + backH;
  const seatWidth = seatRight - seatLeft;
  const cushionW = (seatWidth - cushionGap * 2) / 3;

  return (
    <g transform={transform}>
      {/* Backrest */}
      <rect x={-hw + armW * 0.3} y={-hd} width={width - armW * 0.6} height={backH}
        rx={depth * 0.03} fill="rgba(107,94,79,0.08)" stroke="#6B5E4F"
        strokeWidth={1} vectorEffect="non-scaling-stroke" />

      {/* Left armrest */}
      <rect x={-hw} y={-hd} width={armW} height={depth * 0.92}
        rx={depth * 0.04} fill="rgba(107,94,79,0.06)" stroke="#6B5E4F"
        strokeWidth={1} vectorEffect="non-scaling-stroke" />

      {/* Right armrest */}
      <rect x={hw - armW} y={-hd} width={armW} height={depth * 0.92}
        rx={depth * 0.04} fill="rgba(107,94,79,0.06)" stroke="#6B5E4F"
        strokeWidth={1} vectorEffect="non-scaling-stroke" />

      {/* Three seat cushions */}
      {[0, 1, 2].map(i => (
        <rect key={i}
          x={seatLeft + i * (cushionW + cushionGap)}
          y={seatTop + depth * 0.03}
          width={cushionW}
          height={depth * 0.65}
          rx={depth * 0.04}
          fill="none" stroke="#9E9283"
          strokeWidth={0.5} vectorEffect="non-scaling-stroke"
