          <line key={`seam-${i}`}
            x1={cx} y1={seatTop + depth * 0.15}
            x2={cx} y2={seatTop + depth * 0.55}
            stroke="#9E9283" strokeWidth={0.3} vectorEffect="non-scaling-stroke"
            opacity={0.4} strokeDasharray="3 2" />
