  kitchenTop: 'rgba(232, 213, 183, 0.25)',  // warm tan
  toilet:     'rgba(180, 210, 230, 0.25)',   // cool porcelain blue
  lavatory:   'rgba(180, 210, 230, 0.25)',   // cool porcelain blue
